      find: /(\bfunction\b[\s\S]*?\bmoveSnake\b[\s\S]*?\{[\s\S]*?)(\n\s*\})/m,
      replace: `$1

  // Smooth interpolation between logical grid positions
  const SEGMENT_ANIM_MS = 120;

  if (!state.segmentOffsets) state.segmentOffsets = [];
  if (!state.prevSnake) state.prevSnake = state.snake.map(p => ({ ...p }));
  state.prevSnake = state.snake.map(p => ({ ...p }));

  const now = performance.now();
  state.moveStartedAt = now;
  state.segmentOffsets = state.snake.map((_, i) => {
    if (i === 0) return { x: 0, y: 0 };
    const prev = state.prevSnake[i] || state.prevSnake[i - 1] || state.snake[i];
    const curr = state.snake[i];
    return {
      x: (prev.x - curr.x) * cellSize,
      y: (prev.y - curr.y) * cellSize
    };
  });
$2`
    },
    {
      // add animation frame updater if there is a render loop
      find: /(\bfunction\b[\s\S]*?\brender\b[\s\S]*?\{[\s\S]*?)(\n\s*\})/m,
      replace: `$1
  const t = Math.min(1, (performance.now() - (state.moveStartedAt || 0)) / 120);
  const ease = t * (2 - t); // smooth ease-out
  state.renderEase = ease;
$2`
    },
    {
      // use transforms for snake segments when drawing
      find: /(\bsegment\.style\.left\s*=\s*.*?;\s*\n\s*segment\.style\.top\s*=\s*.*?;)/g,
      replace: `$1
segment.style.transform = \`translate(\${(state.segmentOffsets?.[i]?.x || 0) * (1 - (state.renderEase ?? 1))}px, \${(state.segmentOffsets?.[i]?.y || 0) * (1 - (state.renderEase ?? 1))}px)\`;`
    }
  ]
})

